export default (bucket) => bucket.map((e) => {
  const r = e.value || {};
  const raw = r.ingredient;
  const lines = Array.isArray(raw) ? raw : raw ? [raw] : [];
  const short = lines
    .map((x) => {
      const item = x.ingredient || (x.name !== undefined || x.have !== undefined ? x : {});
      return { name: item.name ?? '?', have: Number(item.have ?? 0), need: Number(x.qty ?? 1) };
    })
    .filter((x) => x.have < x.need);
  const title = r.title ?? '(untitled)';
  return short.length === 0
    ? `${title} \u2014 MAKEABLE`
    : `${title} \u2014 need ${short.map((x) => `${x.need - x.have} ${x.name}`).join(', ')}`;
});
